export function getCategoryMeta(key: string) {
  return TREINO_CATEGORIES.find((c) => c.key === key);
}

export function countByCategory(): Record<string, number> {
  const counts: Record<string, number> = {};
  for (const s of SCENARIOS) counts[s.category] = (counts[s.category] ?? 0) + 1;
  return counts;
}

export function scenariosIn(category: string): Scenario[] {
  return SCENARIOS.filter((s) => s.category === category);
}

/** Pick 1 scenario by date seed — deterministic "treino do dia" (legacy). */
export function getDailyScenario(dateKey: string): Scenario {
  let hash = 0;
  for (let i = 0; i < dateKey.length; i++) {
    hash = (hash * 31 + dateKey.charCodeAt(i)) >>> 0;
  }
  return SCENARIOS[hash % SCENARIOS.length];
}

/** Tema do dia — rotaciona deterministicamente pelos 15 temas.
 *  Em ~15 dias o aluno passa por todos. */
export function getDailyTheme(dateKey: string): string {
  let hash = 0;
  for (let i = 0; i < dateKey.length; i++) {
    hash = (hash * 31 + dateKey.charCodeAt(i)) >>> 0;
  }
  return TREINO_CATEGORIES[hash % TREINO_CATEGORIES.length].key;
}

/** 3 cenários do tema do dia, embaralhados deterministicamente. */
export function getDailyScenarios(dateKey: string, count = 3): Scenario[] {
  const theme = getDailyTheme(dateKey);
  const pool = SCENARIOS.filter((s) => s.category === theme);
  if (pool.length === 0) return SCENARIOS.slice(0, count);

  // Hash secundário pra shuffle determinístico dependente da data
  let hash = 2166136261;
  for (let i = 0; i < dateKey.length; i++) {
    hash ^= dateKey.charCodeAt(i);
    hash = (hash * 16777619) >>> 0;
  }
  const scored = pool.map((s, idx) => ({
    s,
    score: ((hash ^ (s.id.length * 13 + idx * 7)) >>> 0) % 10000,
  }));
  scored.sort((a, b) => a.score - b.score);
  return scored.slice(0, Math.min(count, pool.length)).map((x) => x.s);
}

/** Key do dia no timezone local (YYYY-MM-DD). */
export function todayKey(): string {
  const d = new Date();
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
}
